import { useState, useEffect } from 'react';

function checkNative() {
  try {
    // Capacitor injects window.Capacitor before app loads
    return window.Capacitor?.isNativePlatform?.() || false;
  } catch {
    return false;
  }
}

const isNativePlatform = checkNative();
const MOBILE_BREAKPOINT = 1024;

export default function useIsMobile() {
  const [isMobile, setIsMobile] = useState(
    () => isNativePlatform || (typeof window !== 'undefined' && window.innerWidth <= MOBILE_BREAKPOINT)
  );

  useEffect(() => {
    if (isNativePlatform) return; // Always mobile on native
    const mq = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT}px)`);
    const handler = (e) => setIsMobile(e.matches);
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  return isMobile;
}
